+        _ => None,
+    };
+    let mixed_or_ambiguous = match (&leader, &runner_up) {
+        (Some(leader), Some(runner_up)) => {
+            leader.estimated_time_ns == 0
+                || leader.score_basis_points <= 2_500
+                || leader
+                    .score_basis_points
+                    .saturating_sub(runner_up.score_basis_points)
